import{_ as t,a,b as n,c as i}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as o,o as l,c as d,a2 as s}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Een S3-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/s3.md","filePath":"nl-NL/upload/s3.md","lastUpdated":1781962217000}'),r={name:"nl-NL/upload/s3.md"};function c(p,e,h,u,g,k){return l(),d("div",null,[...e[0]||(e[0]=[s(`<h1 id="een-s3-kanaal-toevoegen" tabindex="-1">Een S3-kanaal toevoegen <a class="header-anchor" href="#een-s3-kanaal-toevoegen" aria-label="Permalink to &quot;Een S3-kanaal toevoegen&quot;">​</a></h1><h2 id="wanneer-dit-geschikt-is" tabindex="-1">Wanneer dit geschikt is <a class="header-anchor" href="#wanneer-dit-geschikt-is" aria-label="Permalink to &quot;Wanneer dit geschikt is&quot;">​</a></h2><p>Gebruik het S3-kanaal wanneer:</p><ul><li>je een S3-compatibele objectopslagdienst wilt koppelen, zoals Cloudflare R2, Backblaze B2, MinIO, AWS S3 of een andere compatibele provider.</li><li>je het standaard S3-configuratiemodel met <code>Endpoint</code>, Access Key en Secret Key wilt gebruiken.</li><li>je niet het native Cloudflare R2-bindingkanaal gebruikt, of je opslagprovider geen Cloudflare R2 is.</li></ul><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vereiste</th><th>Doel</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>De S3 API-endpoint van de objectopslagdienst.</td></tr><tr><td>Bucketnaam</td><td>De bucket waarin bestanden worden opgeslagen.</td></tr><tr><td>Region</td><td>Opslagregio. Voor Cloudflare R2 is dit meestal <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td></tr><tr><td>CDN-domein</td><td>Optioneel aangepast domein voor bestandstoegang.</td></tr></tbody></table><p>Voorbeeld voor Cloudflare R2 via de S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: gekopieerd uit het Cloudflare R2 API-token</span></span>
<span class="line"><span>Secret Access Key: gekopieerd uit het Cloudflare R2 API-token</span></span></code></pre></div><h2 id="waar-je-het-toevoegt" tabindex="-1">Waar je het toevoegt <a class="header-anchor" href="#waar-je-het-toevoegt" aria-label="Permalink to &quot;Waar je het toevoegt&quot;">​</a></h2><ol><li>Open Systeeminstellingen.</li><li>Ga naar Uploadinstellingen.</li><li>Klik rechtsboven op Kanaal toevoegen.</li><li>Selecteer <code>S3</code>.</li></ol><h2 id="veldreferentie" tabindex="-1">Veldreferentie <a class="header-anchor" href="#veldreferentie" aria-label="Permalink to &quot;Veldreferentie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Veld</th><th>Functie</th><th>Verplicht</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td>Een herkenbare naam, bijvoorbeeld <code>s3test</code> of <code>R2-S3</code>.</td><td>Ja</td></tr><tr><td>Kanaal inschakelen</td><td>Bepaalt of dit kanaal meedoet aan uploadselectie.</td><td>Aanbevolen</td></tr><tr><td>Endpoint</td><td>Volledige S3-service-endpoint, inclusief <code>https://</code>.</td><td>Ja</td></tr><tr><td>Aangepast CDN-domein</td><td>Optioneel. Als dit is ingesteld, gebruiken gegenereerde bestandslinks bij voorkeur dit domein.</td><td>Nee</td></tr><tr><td>Bucketnaam</td><td>Bucketnaam, bijvoorbeeld <code>s3test</code> of <code>img-r2</code>.</td><td>Ja</td></tr><tr><td>Bucketregio</td><td>Regio. Voor Cloudflare R2 meestal <code>auto</code>.</td><td>Ja</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td><td>Ja</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td><td>Ja</td></tr><tr><td>Path-style access</td><td>Compatibiliteitsschakelaar. Standaard uit. Sommige MinIO-, OpenList- of zelf gehoste S3-diensten hebben dit nodig.</td><td>Nee</td></tr><tr><td>Quotalimiet</td><td>Bepaalt of dit kanaal op basis van capaciteit wordt meegenomen bij uploads.</td><td>Nee</td></tr><tr><td>Capaciteitslimiet</td><td>Verplicht nadat quotalimiet is ingeschakeld, bijvoorbeeld <code>10 GB</code>.</td><td>Verplicht bij quotalimiet</td></tr><tr><td>Drempel</td><td>Stopt schrijven nadat dit percentage is bereikt, bijvoorbeeld <code>90%</code>.</td><td>Verplicht bij quotalimiet</td></tr><tr><td>Opmerking</td><td>Notities voor eigen beheer.</td><td>Nee</td></tr></tbody></table><h2 id="cloudflare-r2-s3-api-sleutels-maken" tabindex="-1">Cloudflare R2 S3 API-sleutels maken <a class="header-anchor" href="#cloudflare-r2-s3-api-sleutels-maken" aria-label="Permalink to &quot;Cloudflare R2 S3 API-sleutels maken&quot;">​</a></h2><ol><li>Open het Cloudflare Dashboard.</li><li>Ga naar <code>R2 Object Storage</code>.</li><li>Zoek <code>Manage R2 API Tokens</code> of de ingang voor API-tokenbeheer.</li></ol><p>![R2 API-token ingang](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Maak een R2 API-token dat toegang heeft tot de doelbucket.</li></ol><p><img src="`+t+'" alt="Account API-token maken" loading="lazy"></p><ol start="5"><li>Kopieer de gegenereerde <code>Access Key ID</code> en <code>Secret Access Key</code>.</li></ol><p><img src="'+a+'" alt="Tokenwaarden kopiëren" loading="lazy"></p><ol start="6"><li>Ga terug naar de R2-bucketpagina en controleer de bucketnaam.</li><li>Noteer de S3 API-endpoint van het account. Die ziet er meestal zo uit:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="instelstappen" tabindex="-1">Instelstappen <a class="header-anchor" href="#instelstappen" aria-label="Permalink to &quot;Instelstappen&quot;">​</a></h2><ol><li>Open Uploadinstellingen.</li><li>Klik op Kanaal toevoegen.</li><li>Selecteer <code>S3</code>.</li><li>Vul een herkenbare kanaalnaam in, bijvoorbeeld <code>s3test</code>.</li><li>Vul de S3 API-endpoint in bij <code>Endpoint</code>.</li><li>Gebruik je een eigen CDN, vul dat dan in bij <code>Custom CDN domain</code>; anders laat je het leeg.</li><li>Vul de bucketnaam in.</li><li>Vul de regio in. Voor Cloudflare R2 gebruik je in dit voorbeeld <code>auto</code>.</li><li>Vul Access Key ID en Secret Access Key in.</li><li>Laat Path-style access uit, tenzij je provider dit expliciet vereist.</li><li>Wil je capaciteitsbeheer, schakel dan de quotalimiet in en vul capaciteitslimiet en drempel in.</li><li>Klik op Opslaan.</li></ol><p><img src="'+n+'" alt="S3-configuratie toevoegen" loading="lazy"></p><h2 id="controleren" tabindex="-1">Controleren <a class="header-anchor" href="#controleren" aria-label="Permalink to &quot;Controleren&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controle</th><th>Hoe je controleert</th></tr></thead><tbody><tr><td>Kanaalkaart verschijnt</td><td>Na opslaan moet in Uploadinstellingen een S3-kanaalkaart zichtbaar zijn.</td></tr><tr><td>Kanaal is actief</td><td>De schakelaar rechtsboven op de kaart blijft aan.</td></tr><tr><td>Belangrijke velden zijn opgeslagen</td><td>De detailweergave toont Endpoint, Bucket, Region, Path-style access en verwante velden.</td></tr><tr><td>Upload werkt</td><td>Upload een testafbeelding en controleer of het object in de doelbucket verschijnt.</td></tr><tr><td>Link opent</td><td>De afbeeldingslink die na upload wordt teruggegeven opent normaal.</td></tr><tr><td>Capaciteitsweergave werkt</td><td>Als quotalimiet actief is, toont de kaart gebruikte capaciteit en de ingestelde limiet.</td></tr></tbody></table><p>S3-capaciteitsstatistieken worden berekend op basis van ImgBeds lokale bestandsrecords, niet door de bucket realtime bij de provider op te vragen. Na het opslaan van een S3-configuratie berekent het systeem het quota-overzicht opnieuw vanuit de huidige D1-records.</p><p><img src="'+i+`" alt="Quota-opvraag gelukt" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="moet-ik-path-style-access-inschakelen" tabindex="-1">Moet ik Path-style access inschakelen? <a class="header-anchor" href="#moet-ik-path-style-access-inschakelen" aria-label="Permalink to &quot;Moet ik Path-style access inschakelen?&quot;">​</a></h3><p>Meestal niet.</p><p>Schakel dit alleen in als je S3-compatibele provider geen virtual-hosted-style URL&#39;s ondersteunt of als de documentatie dit expliciet vereist. Sommige MinIO-, zelf gehoste S3- en OpenList-compatibele endpoints hebben het nodig.</p><h3 id="waar-is-het-cdn-domein-voor" tabindex="-1">Waar is het CDN-domein voor? <a class="header-anchor" href="#waar-is-het-cdn-domein-voor" aria-label="Permalink to &quot;Waar is het CDN-domein voor?&quot;">​</a></h3><p>Als je een CDN of aangepast toegangsdomein voor de bucket zet, vul je dat hier in.</p><p>Na configuratie gebruikt ImgBed dit domein bij voorkeur voor gegenereerde bestandslinks. Gebruik je geen CDN, laat het veld leeg.</p><h3 id="waarom-mislukt-uploaden" tabindex="-1">Waarom mislukt uploaden? <a class="header-anchor" href="#waarom-mislukt-uploaden" aria-label="Permalink to &quot;Waarom mislukt uploaden?&quot;">​</a></h3><p>Controleer eerst:</p><ol><li>De Endpoint bevat de volledige <code>https://</code>-URL.</li><li>De bucketnaam klopt.</li><li>De Region past bij de eisen van de provider.</li><li>Access Key ID en Secret Access Key zijn volledig gekopieerd.</li><li>De sleutel heeft schrijfrechten op de doelbucket.</li><li>De provider vereist geen Path-style access, of dit is ingeschakeld als het wel nodig is.</li></ol><h2 id="snelle-checklist" tabindex="-1">Snelle checklist <a class="header-anchor" href="#snelle-checklist" aria-label="Permalink to &quot;Snelle checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bereid S3 Endpoint, Bucket, Region, Access Key en Secret Key voor</span></span>
<span class="line"><span>-&gt; Open Uploadinstellingen</span></span>
<span class="line"><span>-&gt; Kanaal toevoegen</span></span>
<span class="line"><span>-&gt; Selecteer S3</span></span>
<span class="line"><span>-&gt; Vul Endpoint / Bucket / Region / Access Key / Secret Key in</span></span>
<span class="line"><span>-&gt; Vul eventueel een CDN-domein in</span></span>
<span class="line"><span>-&gt; Laat Path-style access standaard uit</span></span>
<span class="line"><span>-&gt; Schakel quotalimiet in als dat nodig is</span></span>
<span class="line"><span>-&gt; Sla op</span></span>
<span class="line"><span>-&gt; Upload een testafbeelding en controleer het resultaat</span></span></code></pre></div>`,40)])])}const f=o(r,[["render",c]]);export{v as __pageData,f as default};
